#!/bin/bash
set -e

# This script is generated by build.sh. Do not edit directly.


packages=(
  sudo
  git
  gh
  curl
  btop
  fastfetch
  unzip # required for bun installation
)

desktop_packages=(
  gnome-session
  gnome-shell
  gdm3
  gvfs
  gvfs-backends
  network-manager-gnome
  nautilus
  gnome-terminal
  gnome-tweaks
  gnome-text-editor
  gnome-system-monitor
  xdg-desktop-portal-gnome
  fonts-cantarell
)

declare -A other_packages=(
  [node]='wget -qO- https://deb.nodesource.com/setup_lts.x | sudo -E bash - && sudo apt-get install -y nodejs'
  [bun]='su - "$(get_real_user)" -c "wget -qO- https://bun.sh/install | bash"'
  [docker]='wget -qO- https://get.docker.com | sudo sh && sudo usermod -aG docker "$(get_real_user)"'
  [rustc]='su - "$(get_real_user)" -c "wget -qO- https://sh.rustup.rs | sh -s -- -y"'
  [go]='GOVER=$(wget -qO- "https://go.dev/VERSION?m=text" | head -n1) && wget -qO- "https://go.dev/dl/${GOVER}.linux-amd64.tar.gz" | sudo tar -C /usr/local -xz && echo "export PATH=\$PATH:/usr/local/go/bin" | sudo tee /etc/profile.d/go.sh > /dev/null'
)

declare -A other_desktop_packages=(
  [brave]='wget -qO- https://dl.brave.com/install.sh | sh'
)


# Set fastfetch configuration
# Usage: setup_fastfetch
# Returns: 0 on success, 1 on failure
setup_fastfetch() {
  logger info "setting up fastfetch configuration..."

	local fastfetch_dir="$HOME/.config/fastfetch"
	local config_file="$fastfetch_dir/config.jsonc"
	
	# create directory if it doesn't exist
	if [ ! -d "$fastfetch_dir" ]; then
		mkdir -p "$fastfetch_dir" || {
			logger error "failed to create fastfetch directory"
			return 1
		}
	fi
	
	# create the configuration file
	cat > "$config_file" << 'EOF'
{
  "$schema": "https://github.com/fastfetch-cli/fastfetch/raw/dev/doc/json_schema.json",
  "logo": {
    "type": "data",
    "source": "\u001b[97m  ▄▀▄▀▀▀▀▄▀▄\n  █        ▀▄      ▄\n █  ▀  ▀     ▀▄▄  █ █\n █ ▄ █▀ ▄       ▀▀  █\n █  ▀▀▀▀            █\n █                  █\n █                  █\n  █  ▄▄  ▄▄▄▄  ▄▄  █\n  █ ▄▀█ ▄▀  █ ▄▀█ ▄▀\n   ▀   ▀     ▀   ▀\u001b[0m",
    "padding": {
      "top": 1,
      "left": 1
    }
  },
  "display": {
    "color": {
      "keys": "90",
      "title": "90"
    }
  },
  "modules": [
    "title",
    "separator",
    "os",
    "host",
    "kernel",
    "uptime",
    "packages",
    "shell",
    "wm",
    "terminal",
    "cpu",
    "gpu",
    "memory",
    "swap",
    "disk",
    "localip",
    "battery",
    "locale"
  ]
}
EOF
	
  echo "fastfetch configuration created at $config_file"

	if [ $? -eq 0 ]; then
		logger done "fastfetch configuration updated"
		return 0
	else
		logger error "failed to update fastfetch configuration"
		return 1
	fi
}


install_packages() {  
  apt install -y "${packages[@]}"

  for package in "${!other_packages[@]}"; do
    local install_cmd="${other_packages[$package]}"
    if ! command -v "$package" &> /dev/null; then
      logger info "installing $package..."
      eval "$install_cmd" || logger error "failed to install $package"
    else
      echo "$package is already installed."
    fi
  done
}

install_desktop_packages() {
  apt install -y --no-install-recommends "${desktop_packages[@]}"
  
  for package in "${!other_desktop_packages[@]}"; do
    local install_cmd="${other_desktop_packages[$package]}"
    if ! command -v "$package" &> /dev/null; then
      logger info "installing $package..."
      eval "$install_cmd" || logger error "failed to install $package"
    else
      echo "$package is already installed."
    fi
  done
}


print_help() {
	echo "Usage: $0 [OPTIONS]"
	echo ""
	echo "OPTIONS:"
	echo "  -h, --help					Show this help message"
	echo ""
}

# Parse command line arguments
# Usage: parse_arguments "$@"
# Sets global variables: INSTALLATION_ERROR
parse_arguments() {
	# Initialize default values
	SHOW_EFFECTS=false
	INSTALLATION_ERROR=false
	
	while [[ $# -gt 0 ]]; do
		case "$1" in
			-h|--help)
				print_help
				exit 0
				;;
			-*)
				# Handle combined short flags
				flags=$(echo "$1" | sed 's/^-//')
				for flag in $(echo "$flags" | fold -w1); do
					case "$flag" in
						e)
							# Count 'e' flags to determine behavior
							e_count=$(echo "$flags" | grep -o 'e' | wc -l)
							if [ $e_count -eq 1 ]; then
								SHOW_EFFECTS=true
							elif [ $e_count -gt 1 ]; then
								# Multiple 'e's means effects + errored
								SHOW_EFFECTS=true
								FORCE_ERROR=true
							fi
							;;
						*)
							echo "Unknown option: -$flag"
							print_help
							exit 1
							;;
					esac
				done
				shift
				;;
			*)
				echo "Unknown option: $1"
				print_help
				exit 1
				;;
		esac
	done
}


# Usage: confirm "Prompt message" | confirm "Prompt message" "Y" | confirm "Prompt message" "N"
# Returns: 0 for yes, 1 for no
confirm() {
  local prompt="$1"
  local default="${2:-}"  # Optional: "Y" or "N"
  local answer

  while true; do
    if [ "$default" = "Y" ] || [ "$default" = "y" ]; then
      read -rp "$prompt [Y/n]: " answer
    elif [ "$default" = "N" ] || [ "$default" = "n" ]; then
      read -rp "$prompt [y/N]: " answer
    else
      read -rp "$prompt [y/n]: " answer
    fi

    answer="${answer,,}"  # to lowercase

    case "$answer" in
      y|yes) return 0 ;;
      n|no)  return 1 ;;
      "") 
        # Enter pressed - use default if set
        if [ "$default" = "Y" ] || [ "$default" = "y" ]; then
          return 0
        elif [ "$default" = "N" ] || [ "$default" = "n" ]; then
          return 1
        else
          echo "Please answer yes or no."
        fi
        ;;
      *) echo "Please answer yes or no." ;;
    esac
  done
}


# Usage: logger <method> <message>
# Methods: info, done, error, warn
logger() {
	local method="$1"
	local message="$2"
	
	case "$method" in
		"info")
			echo -e "\033[44m INFO \033[0m $message"
			;;
		"done")
			echo -e "\033[42m DONE \033[0m $message"
			;;
		"error")
			echo -e "\033[41m ERROR \033[0m $message"
			;;
		"warn")
			echo -e "\033[43m WARN \033[0m $message"
			;;
		*)
			echo "Unknown logger method: $method"
			return 1
			;;
	esac
}


# Check if the script is running as root
# Returns 0 if yes, 1 otherwise
is_running_as_root() {
  if [ "$(id -u)" -eq 0 ]; then
    return 0
  else
    return 1 
  fi
}

# Get the real user who invoked the script, even if run with sudo or pkexec
get_real_user() {
  if [ -n "${SUDO_USER:-}" ]; then
    echo "$SUDO_USER"
  elif command -v logname &>/dev/null && logname 2>/dev/null; then
    return
  elif [ -n "${PKEXEC_UID:-}" ]; then
    id -un "$PKEXEC_UID"
  elif [ -n "${ORIGINAL_USER:-}" ]; then
    echo "$ORIGINAL_USER"
  else
    echo "${USER:-$(whoami)}"
  fi
}

setup_sudoers() {
  local users=("$@")
  local gray="\033[90m"
  local reset="\033[0m"

  logger info "setting up passwordless sudo for users: ${gray}${users[*]}${reset}"

  # if no users are provided, default to the current user
  if [ ${#users[@]} -eq 0 ]; then
    users=("$USER")
  fi

  # Loop through each user and set up passwordless sudo
  for user in "${users[@]}"; do
    # skip if the user is empty
    if [ -z "$user" ]; then
      continue
    fi
    
    # skip if the user is root
    if [ "$user" = "root" ]; then
      echo "skipping user: ${gray}${user}${reset}"
      continue
    fi

    # check if the user already has passwordless sudo
    local user_pattern="^[[:space:]]*${user}[[:space:]]+"
    local perm_pattern="ALL=\(ALL(:ALL)?\)[[:space:]]+"
    local nopasswd_pattern="NOPASSWD:[[:space:]]*ALL"
    local sudoers_regex="${user_pattern}${perm_pattern}${nopasswd_pattern}"

    if grep -rEq "$sudoers_regex" /etc/sudoers /etc/sudoers.d/ 2>/dev/null; then
      echo "alreadty has passwordless sudo: ${gray}${user}${reset}"
      continue
    fi

    # create a sudoers file for the user with passwordless sudo
    local sudoers_file="/etc/sudoers.d/99-${user}-nopasswd"

    cat > "$sudoers_file" << EOF
$user ALL=(ALL) NOPASSWD:ALL
EOF

    # lock down permissions, then validate before trusting the file;
    # roll back on failure so a bad file never lingers in sudoers.d
    chmod 0440 "$sudoers_file"
    /usr/sbin/visudo -cf "$sudoers_file" || {
      logger error "failed to validate sudoers file for $user"
      rm -f "$sudoers_file"
      return 1
    }

    logger info "passwordless sudo setup completed for user: ${gray}${user}${reset}"
  done
}


parse_arguments "$@"
is_running_as_root || { logger error "run this script as root (or via su -c)."; exit 1; }
logger info "starting installation script..."

confirm "Install minimal desktop apps?" && INSTALL_DESKTOP="y" || INSTALL_DESKTOP="n"

logger info "installing packages..."
apt update
install_packages

setup_fastfetch

setup_sudoers "$(get_real_user)"

if [ "$INSTALL_DESKTOP" = "y" ]; then
  logger info "installing desktop packages..."
  install_desktop_packages
fi

logger done "installation script completed"
confirm "Reboot now?" "Y" && sudo reboot now || logger info "reboot later to apply changes"

